    CommonModule, // Required for NgIf
    ReactiveFormsModule,
    AutoCompleteModule,
    ButtonModule,
    CalendarModule,
    FloatLabelModule,
    MultiSelectModule,
    TextareaModule,
    InputGroupModule,
    NgIf,
    Select,
    DatePickerModule,
    // Explicitly imported if standalone
