  allergyTypes: Option[] = [
    { name: 'Médicament', value: 'Médicament' },
    { name: 'Aliment', value: 'Aliment' },
    { name: 'Environnement', value: 'Environnement' },
    { name: 'Autre', value: 'Autre' },
  ];

  // Store all possible allergens with their types
