  --_padding: 0 var(--ft-unit-300);
  --_balanced_small_padding: 0;
  --_gap: var(--ft-unit-300);
  --_icon-size: 20px;

  display: flex;
  align-items: center;

  .button-wrapper {
    display: flex;
    align-items: center;
    height: var(--_height);
    padding: var(--_padding);
    gap: var(--_gap);
    background-color: var(--_bg);
    color: var(--_text);
    border: var(--ft-border-secondary) solid var(--_border-color);
    box-shadow: var(--_shadow);
    width: fit-content;

    .content-section {
      display: flex;
      flex-direction: column;

      .label-row {
        display: flex;
        height: fit-content;
      }
    }

    .suffix-icon .suffix, .prefix-icon {
      align-items: center;
      justify-content: center;
      display: flex;
    }

    /* Specific Icon Adjustments */

    &:has(.prefix-icon) {
      padding-left: var(--_balanced_small_padding);
    }

    &:has(.suffix-icon) {
      padding-right: var(--_balanced_small_padding);
    }

    /* Combined Rule: If it has EITHER icon, but NO content and NOT BOTH icons,
       apply balanced small padding */

    &:not(:has(.content-section)) {
      &:has(.prefix-icon):not(:has(.suffix-icon)),
      &:has(.suffix-icon):not(:has(.prefix-icon)) {
        padding: 0 var(--_balanced_small_padding);
      }
    }

    [class*="material-symbols-rounded"] {
      font-size: var(--_icon-size);
    }
  }

  /* 2. COLOR THEME LOGIC (The Mixin Logic) */

  &.primary {
    --_brand: var(--ft-color-primary);
  }

  &.secondary {
    --_brand: var(--ft-color-secondary);
  }

  &.tertiary {
    --_brand: var(--ft-color-tertiary);
  }

  &.success {
    --_brand: var(--ft-color-success);
  }

  &.warning {
    --_brand: var(--ft-color-warning);
  }

  &.danger {
    --_brand: var(--ft-color-danger);
  }

  /* 3. VARIANT LOGIC (Collapsing Flat, Outlined, Faded, Ghost) */

  /* FLAT: Solid background, shadow uses color-mix */

  &.flat {
    --_bg: var(--_brand);
    --_text: var(--ft-color-on-primary);
    --_border-color: transparent;
    --_brand_variant: var(--_brand);

    --_shadow: 0 var(--_vertical-offset) var(--_shadow-blur) color-mix(in srgb, var(--_brand_variant) 30%, transparent);

    &.hover {
      --_brand_variant: color-mix(in srgb, var(--_brand) 80%, black);
      --_bg: var(--_brand-600, var(--_brand_variant));
    }

    &.press {
      --_brand_variant: color-mix(in srgb, var(--_brand) 60%, black);
      --_bg: var(--_brand-700, color-mix(in srgb, var(--_brand) 60%, black));
    }

    &.focus {
      --_brand_variant: color-mix(in srgb, var(--_brand) 40%, black);
      --_bg: var(--_brand-900, color-mix(in srgb, var(--_brand) 40%, black));
    }
  }

  /* OUTLINED: Border changes on hover/press */

  &.outlined {
    &.hover {
      --_border-color: var(--_brand);
    }

    &.press {
      --_border-color: var(--_brand);
      --_bg: color-mix(in srgb, var(--_brand) 10%, transparent);
    }

    &.focus {
      --_border-color: var(--_brand);
      --_bg: color-mix(in srgb, var(--_brand) 20%, transparent);
    }

    &.disabled {
      --_bg: transparent;
    }
  }

  /* FADED: Light background, colored text */

  &.faded {
    --_bg: var(--ft-form-field-100);
    --_text: var(--_brand);
    --_border-color: transparent;

    &.hover {
      --_text: var(--_brand-600, color-mix(in srgb, var(--_brand) 80%, black));
      --_bg: color-mix(in srgb, var(--_brand) 20%, transparent);
    }

    &.press {
      --_text: var(--_brand-700, color-mix(in srgb, var(--_brand) 60%, black));
      --_bg: color-mix(in srgb, var(--_brand) 30%, transparent);
    }

    &.focus {
      --_text: var(--_brand-900, color-mix(in srgb, var(--_brand) 40%, black));
      --_bg: color-mix(in srgb, var(--_brand) 40%, transparent);
    }
  }

  &.ghost {
    /*--_bg: var(--_brand);*/
    --_text: var(--_brand);
    --_border-color: transparent;
    --_shadow: none;

    &.hover {
      --_text: var(--_brand-600, color-mix(in srgb, var(--_brand) 80%, black));
    }

    &.press {
      --_text: var(--_brand-700, color-mix(in srgb, var(--_brand) 60%, black));
    }

    &.focus {
      --_text: var(--_brand-900, color-mix(in srgb, var(--_brand) 40%, black));
    }

    &.disabled {
      --_bg: transparent;
    }
  }

  /* 4. SIZE LOGIC (Collapsing XS, SM, MD, LG) */

  &.xs-size {
    --_height: var(--ft-unit-600);
    --_padding: 0 var(--ft-unit-200);
    --_balanced_small_padding: var(--ft-unit-100);
    --_gap: var(--ft-unit-100);
    --_icon-size: 16px;
    --_vertical-offset: 2px;
    --_shadow-blur: 12px;
  }

  &.sm-size {
    --_height: var(--ft-unit-700);
