    --_balanced_small_padding: var(--ft-unit-150);
    --_gap: var(--ft-unit-150);
    --_icon-size: 18px;
    --_vertical-offset: 4px;
    --_shadow-blur: 16px;
  }

  &.md-size {
    --_height: var(--ft-unit-800);
    --_padding: 0 var(--ft-unit-400);
    --_balanced_small_padding: var(--ft-unit-200);
    --_gap: var(--ft-unit-200);
    --_icon-size: 20px;
    --_vertical-offset: 6px;
    --_shadow-blur: 20px;
  }

  &.lg-size {
    --_height: var(--ft-unit-900);
    --_padding: 0 var(--ft-unit-500);
    --_balanced_small_padding: var(--ft-unit-300);
    --_gap: var(--ft-unit-300);
    --_icon-size: 24px;
    --_vertical-offset: 8px;
    --_shadow-blur: 24px;
  }

  /* 5. SPECIAL CASE: DISABLED */

  &.disabled {
    --_text: var(--ft-color-on-surface-muted);
