::ng-deep storybook-root {
  > ft-input {
    min-width: 200px;
    width: fit-content !important;
    display: block;
  }
}

:host {
  width: 100%;
}


.field-container {
  /* INTERNAL VARIABLE DEFAULTS (The "Mixin" Arguments) */
  --_field-bg: transparent;
  --_field-border-color: var(--ft-color-border-200);
  --_field-border-width: var(--ft-border-secondary);
  --_field-text: var(--ft-color-solid-on-surface);
  --_field-placeholder: var(--ft-color-on-surface-level-300);
  --_field-label: var(--ft-color-on-surface-level-100);

  --_balanced_small_padding: var(--ft-unit-400);
  --_field-height: var(--ft-unit-800);
  --_field-padding: 0 var(--ft-unit-400);
  --_field-gap: var(--ft-unit-300);
  --_field-container-gap: var(--ft-unit-100);
  --_field-icon-size: 20px;
  --_field-content-gap: var(--ft-unit-100);

  display: grid;
  width: 100%;
  gap: var(--_field-container-gap);

  /* BASE LAYOUT & CHILD STYLES */

  .input-wrapper {
    display: flex;
    align-items: center;
    min-width: 100%;
    height: var(--_field-height);
    padding: var(--_field-padding);
    gap: var(--_field-gap);
    background-color: var(--_field-bg);
    border: var(--_field-border-width) solid var(--_field-border-color);
    color: var(--_field-text);
    transition: all 0.2s ease;

    .content-section {
      display: flex;
      flex-direction: column;
      flex-grow: 1;
      gap: var(--_field-content-gap);
      min-width: 0;

      .placeholder, .content {
        line-height: normal;
      }

      .placeholder {
        color: var(--_field-placeholder);
      }

      .content {
        color: var(--_field-text);
      }
    }

    .prefix-icon, .suffix-icon .suffix {
      display: flex;
      align-items: center;
    }

    .suffix-icon {
      gap: var(--ft-unit-100);
    }

    &:has(.prefix-icon) {
      padding-left: var(--_balanced_small_padding);
    }

    &:has(.suffix-icon) {
      padding-right: var(--_balanced_small_padding);
    }

    [class*="material-symbols-rounded"] {
      font-size: var(--_field-icon-size);
    }
  }

  .label-row {
    color: var(--_field-label);
    display: contents;
  }

  .description p, .error-text {
    line-height: 1;
  }

  .error-text {
    color: var(--ft-color-danger);
  }

  &.label-inside {
    --_field-label: var(--ft-color-on-surface-level-300);
  }


  /* STATE LOGIC (Overrides variants) */

  &.invalid {
    --_field-label: var(--ft-color-danger);
    --_field-bg: var(--ft-color-danger-50);
    --_field-border-color: var(--ft-color-danger);
    --_field-border-width: var(--ft-border-secondary);
  }

  &.disabled {
    pointer-events: none;
    --_field-text: var(--ft-color-on-surface-muted);
    --_field-label: var(--ft-color-on-surface-muted);
    --_field-placeholder: var(--ft-color-on-surface-muted);
    --_field-bg: var(--ft-form-field-muted);
    --_field-border-color: var(--ft-color-border-muted);
  }

  /* SIZE LOGIC */

  &.xs-size {
    --_field-height: var(--ft-unit-500);
    --_balanced_small_padding: var(--ft-unit-150);
    --_field-padding: 0 var(--ft-unit-200);
    --_field-gap: var(--ft-unit-200);
    --_field-icon-size: 16px;
    --_field-content-gap: var(--ft-unit-0);
    --_field-border-width: var(--ft-border-primary);

    &.label-inside {
      --_field-height: var(--ft-unit-1000);
      --_balanced_small_padding: var(--ft-unit-200);
      --_field-padding: 0 var(--ft-unit-300);

      .rounded-full {
        --_balanced_small_padding: var(--ft-unit-300);
        --_field-padding: 0 var(--ft-unit-400);
      }
    }
  }

  &.sm-size {
    --_field-height: var(--ft-unit-600);
    --_balanced_small_padding: var(--ft-unit-200);
    --_field-padding: 0 var(--ft-unit-300);
    --_field-gap: var(--ft-unit-200);
    --_field-icon-size: 16px;
    --_field-content-gap: var(--ft-unit-50);

    &.label-inside {
      --_field-height: var(--ft-unit-1200);
      --_balanced_small_padding: var(--ft-unit-300);
      --_field-padding: 0 var(--ft-unit-400);
      --_field-gap: var(--ft-unit-300);

      .rounded-full {
        --_balanced_small_padding: var(--ft-unit-400);
        --_field-padding: 0 var(--ft-unit-500);
      }
    }
  }

  &.md-size {
    --_field-height: var(--ft-unit-800);
    --_balanced_small_padding: var(--ft-unit-200);
    --_field-padding: 0 var(--ft-unit-300);
    --_field-gap: var(--ft-unit-200);
    --_field-icon-size: 20px;
    --_field-content-gap: var(--ft-unit-100);

    &.label-inside {
      --_field-height: var(--ft-unit-1400);
      --_balanced_small_padding: var(--ft-unit-300);
      --_field-padding: 0 var(--ft-unit-400);
      --_field-gap: var(--ft-unit-300);

      .rounded-full {
        --_balanced_small_padding: var(--ft-unit-400);
        --_field-padding: 0 var(--ft-unit-500);
      }
    }
  }

  &.lg-size {
    --_field-height: var(--ft-unit-900);
    --_balanced_small_padding: var(--ft-unit-300);
    --_field-padding: 0 var(--ft-unit-400);
    --_field-gap: var(--ft-unit-400);
    --_field-icon-size: 24px;
    --_field-content-gap: var(--ft-unit-150);

    &.label-inside {
      --_field-height: var(--ft-unit-1600);
      --_balanced_small_padding: var(--ft-unit-400);
      --_field-padding: 0 var(--ft-unit-500);

      .rounded-full {
        --_balanced_small_padding: var(--ft-unit-500);
        --_field-padding: 0 var(--ft-unit-600);
      }
    }
  }

  /* VARIANT LOGIC */

  &.flat {
    --_field-bg: var(--ft-form-field-100);
    --_field-border-width: 0px;

    &.hover {
      --_field-bg: var(--ft-form-field-200);
    }

    &.readonly {
      --_field-bg: var(--ft-form-field-50);
    }
  }

  &.faded {
    --_field-bg: var(--ft-form-field-100);

    &.hover {
      --_field-bg: var(--ft-form-field-200);
    }

    &.focus {
      --_field-bg: var(--ft-form-field-200);
      --_field-border-color: var(--ft-color-primary);
    }

    &.readonly {
      --_field-bg: var(--ft-form-field-50);
      --_field-border-color: var(--ft-color-border-100);
    }
  }

  &.outlined {
    --_field-bg: transparent !important;

    &.hover {
      --_field-border-color: var(--ft-color-border-300);
    }

    &.focus {
      --_field-border-color: var(--ft-color-primary);
    }

    &.readonly {
      --_field-border-color: var(--ft-color-border-100);
    }
  }

  &.ghost {
    --_field-border-width: 0px;
    --_field-bg: transparent;

    &.label-outside-left, &.label-outside {
      .content {
        --_field-text: var(--ft-color-on-surface-level-300);
      }
    }


    &.invalid {
      --_field-text: var(--ft-color-danger);
      /*--_field-placeholder: var(--ft-color-danger);*/
    }

    &.hover, &.focus {
      /*--_field-bg: var(--ft-form-field-50);*/
    }
  }

  /* LAYOUT MODES (Grid Positioning) */

  &.label-inside {
    .input-wrapper {
      grid-area: 1 / 1;
    }

    .error-message, .description {
      grid-area: 2 / 1;
    }
  }

  &.label-outside {
    .label-row {
      grid-area: 1 / 1;
    }

    .input-wrapper {
      grid-area: 2 / 1;
    }

    .error-message, .description {
      grid-area: 3 / 1;
    }
  }

  &.label-outside-left {
    grid-template-columns: fit-content(50%) auto;
    column-gap: var(--_field-gap);

    .label-row {
      grid-area: 1 / 1;
    }

    .input-wrapper {
      grid-area: 1 / 2;
    }

    .error-message, .description {
      grid-area: 2 / 2;
    }
  }

  &.invalid {
    --_field-border-color: var(--ft-color-danger);
    /*--_field-bg: var(--ft-color-danger-50);*/
  }

  &.focus {
    --_field-label: var(--ft-color-primary)
  }
}


