    { name: 'Paracétamol', type: 'Substance active' },
    { name: 'Doliprane', type: 'Nom du médicament' }, // Example Drug Name
    { name: 'Spedifen', type: 'Nom du médicament' }, // Example Drug Name
    // Add more as needed
  ];

